import { useEffect, useRef, useState } from "react";

function useCounter(target: number, duration = 1200) {
  const [count, setCount] = useState(0);
  const ref = useRef<HTMLDivElement>(null);
  const started = useRef(false);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting && !started.current) {
          started.current = true;
          const start = performance.now();
          const animate = (now: number) => {
            const progress = Math.min((now - start) / duration, 1);
            const ease = 1 - Math.pow(1 - progress, 3);
            setCount(Math.floor(ease * target));
            if (progress < 1) requestAnimationFrame(animate);
          };
          requestAnimationFrame(animate);
        }
      },
      { threshold: 0.5 }
    );
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, [target, duration]);

  return { count, ref };
}

const STATS = [
  { value: 18000, suffix: "+", label: "Aktive Teams", prefix: "" },
  { value: 99, suffix: ".97%", label: "Uptime SLA", prefix: "" },
  { value: 4, suffix: "M+", label: "Generierte Seiten", prefix: "" },
  { value: 140, suffix: "+", label: "Länder", prefix: "" },
];

function StatItem({ value, suffix, label, prefix }: typeof STATS[0]) {
  const { count, ref } = useCounter(value);
  return (
    <article ref={ref} className="text-center">
      <p className="text-4xl font-black text-violet-600 sm:text-5xl">
        {prefix}{count.toLocaleString("de-DE")}{suffix}
      </p>
      <p className="mt-2 text-sm font-medium text-slate-500">{label}</p>
    </article>
  );
}

